def boolean_retrieve(query_expr: str, index: dict, total_docs: int) -> list:
    all_docs = set(range(total_docs))

    def get_docs(term: str) -> set:
        return set(index.get(term, []))

    def complement(docs: set) -> set:
        return all_docs - docs

    tokens = query_expr.strip().split()
    if not tokens:
        return []

    # Parse: evaluate left to right with AND/OR/NOT
    # Handle first operand
    i = 0
    if tokens[i] == 'NOT':
        i += 1
        result = complement(get_docs(tokens[i]))
        i += 1
    else:
        result = get_docs(tokens[i])
        i += 1

    while i < len(tokens):
        op = tokens[i]
        i += 1
        if op == 'AND':
            if i < len(tokens) and tokens[i] == 'NOT':
                i += 1
                operand = complement(get_docs(tokens[i]))
            else:
                operand = get_docs(tokens[i])
            result = result & operand
            i += 1
        elif op == 'OR':
            if i < len(tokens) and tokens[i] == 'NOT':
                i += 1
                operand = complement(get_docs(tokens[i]))
            else:
                operand = get_docs(tokens[i])
            result = result | operand
            i += 1
        else:
            # Unexpected token — treat as implicit AND
            result = result & get_docs(op)

    return sorted(result)

