index = {'cat': [0, 1, 3], 'dog': [1, 2]}
result = boolean_retrieve('cat', index, total_docs=5)
assert result == [0, 1, 3], f"Expected [0,1,3]: {result}"

index = {'cat': [0, 1, 3], 'dog': [1, 2, 3]}
result = boolean_retrieve('cat AND dog', index, total_docs=5)
assert result == [1, 3], f"cat AND dog should be [1,3]: {result}"

index = {'cat': [0, 2], 'dog': [1, 2]}
result = boolean_retrieve('cat OR dog', index, total_docs=4)
assert result == [0, 1, 2], f"cat OR dog should be [0,1,2]: {result}"

index = {'cat': [0, 1, 2]}
result = boolean_retrieve('NOT cat', index, total_docs=4)
assert result == [3], f"NOT cat with 4 docs should be [3]: {result}"

index = {'cat': [0, 1, 2, 3], 'dog': [1, 3]}
result = boolean_retrieve('cat AND NOT dog', index, total_docs=5)
assert result == [0, 2], f"cat AND NOT dog should be [0,2]: {result}"
